+  // Spawn new writes
+  for (let s = 0; s < spawns; s++) {
+    const color = COLORS[nextId % COLORS.length];
+    left.push({ id: nextId, color, x: 8, state: "queued", progress: 0, batchId: 0 });
+    right.push({ id: nextId, color, x: 8, state: "queued", progress: 0, batchId: 0 });
+    nextId++;
+  }
