+  for (const w of left) {
+    if (w.state === "queued") {
+      w.x = Math.min(w.x + dt * 80, QUEUE_X - 10);
+      if (!lockTaken && w.x >= QUEUE_X - 14) {
+        w.state = "committing";
+        w.progress = 0;
+        lockTaken = true;
+      } else if (lockTaken && w.x >= QUEUE_X - 14 && Math.random() < dt * 0.3) {
+        // Occasional lock error under contention
+        w.state = "error";
+        w.progress = 0;
+        leftErrors++;
+      }
+    } else if (w.state === "committing") {
