+        w.progress = 0;
+        leftCommits++;
+        leftMessages++;
+      }
+    } else if (w.state === "error") {
+      w.progress += dt * 2;
+      if (w.progress >= 1) {
+        // Retry
+        w.state = "queued";
+        w.x = 20 + Math.random() * 30;
+        w.progress = 0;
+      }
+    } else if (w.state === "done") {
+      w.progress += dt * 3;
+      if (w.progress >= 1) {
+        // Remove completed ops to prevent unbounded growth
+        w.state = "done";
+        w.progress = 2; // Mark for cleanup
+      }
