+  const dt = deltaMs / 1000;
+  let {
+    sqliteWrites,
+    gitCommits,
+    gitBatchQueue,
+    gitBatchTimer,
+    nextId,
+    spawnTimer,
+  } = prev;
+
+  const particles = prev.particles.map((p) => ({ ...p }));
