+  // Advance particles
+  const sqliteSpeed = 1.2;
+  const gitSpeed = 0.8;
+
+  for (const p of particles) {
+    const speed = p.path === "sqlite" ? sqliteSpeed : gitSpeed;
+    p.progress += dt * speed;
