+  return {
+    particles: activeParticles.slice(-30), // Cap to prevent unbounded growth
+    sqliteWrites,
+    gitCommits,
+    gitBatchQueue,
+    gitBatchTimer,
+    searchQueries: prev.searchQueries,
+    auditReads: prev.auditReads,
+    elapsed: prev.elapsed + deltaMs,
